import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Calendar, Trash, ArrowLeft, Tag, X, Eye
} from 'lucide-react';

// --- ESTILOS ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif', background: '#f8fafc', minHeight: '100vh' };
const topNav = { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const sidebarTitle = { margin: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.8rem' };
const tableWrapper = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px' };
const mainTable = { width: '100%', borderCollapse: 'collapse' };
const thCell = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.85rem', background: '#f8fafc' };
const tdCell = { padding: '10px', borderBottom: '1px solid #f1f5f9' };
const inputTable = { width: '100%', border: 'none', outline: 'none', padding: '10px', background: 'transparent' };
const btnNuevaSucursalCustom = { background: '#1e293b', color: 'white', padding: '12px 25px', borderRadius: '12px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };

// --- COMPONENTE PRINCIPAL ---
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaNueva = () => ({
    id: Date.now() + Math.random(),
    producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null
  });

  const [filas, setFilas] = useState([filaNueva()]);
  const [publicados, setPublicados] = useState([]); // <--- AQUÍ VERÁS LO QUE PUBLICASTE
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [showGaleria, setShowGaleria] = useState(false);

  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  // CARGAR PRODUCTOS YA PUBLICADOS
  const cargarPublicados = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setPublicados(res.data);
    } catch (e) {
      console.error("Error cargando publicados", e);
    }
  };

  useEffect(() => {
    cargarPublicados();
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data));
  }, [localId]);

  const eliminarOferta = async (id) => {
    if(!window.confirm("¿Seguro quieres borrar esta oferta?")) return;
    try {
      await axios.delete(`${API_URL}/api/ofertas/${id}`);
      cargarPublicados(); // Recarga la lista
    } catch (e) { alert("No se pudo eliminar"); }
  };

  const publicarOfertas = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Define las fechas.");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precioNuevo) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precioNuevo),
          precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock),
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId,
          categoria: f.categoria,
          publicado: true,
          fechaInicioOferta: fechas.inicio,
          fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      alert("¡Publicado con éxito!");
      setFilas([filaNueva()]);
      cargarPublicados(); // <--- ACTUALIZA LA VISTA AUTOMÁTICAMENTE
    } catch (e) { alert("Error al guardar."); } finally { setCargando(false); }
  };

  // (Funciones buscarMatch, handlePaste, actualizarFila se mantienen igual...)
  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    const nuevas = lineas.map(line => {
        const celdas = line.split('\t');
        return { ...filaNueva(), id: Math.random(), producto: celdas[0] || '', precioNuevo: celdas[1] || '', precioViejo: celdas[2] || '', stock: celdas[3] || 0, categoria: celdas[4] || 'Almacén', fotoSugerida: buscarMatch(celdas[0]) };
    });
    setFilas(nuevas);
  };

  return (
    <div style={containerStyle}>
      {/* ... (Encabezado igual) ... */}
      <div style={topNav}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <button onClick={() => setShowGaleria(true)} style={{...btnNuevaSucursalCustom, background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22'}}><Database size={16}/> Galería</button>
      </div>

      <div style={{marginBottom: '20px'}}>
        <h1 style={sidebarTitle}><Sparkles color="#e67e22"/> Nueva Carga Masiva</h1>
      </div>

      {/* SECCIÓN 1: EDITOR / CARGA */}
      <div style={tableWrapper} onPaste={handlePaste}>
        <table style={mainTable}>
           {/* ... (Thead y Tbody de carga igual al anterior) ... */}
           <thead><tr style={{background:'#f8fafc'}}><th style={thCell}>Foto</th><th style={thCell}>Producto</th><th style={thCell}>P. Nuevo</th><th style={thCell}>P. Viejo</th><th style={thCell}>Stock</th><th style={thCell}></th></tr></thead>
           <tbody>
             {filas.map(f => (
               <tr key={f.id}><td style={tdCell}>{f.fotoSugerida ? <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_50,c_fill/v1/${f.fotoSugerida.publicId}`} style={{borderRadius:'8px'}} alt="preview"/> : <ImageIcon color="#cbd5e1"/>}</td>
               <td style={tdCell}><input style={inputTable} value={f.producto} onChange={e => {
                 const n = [...filas];
                 const idx = n.findIndex(x => x.id === f.id);
                 n[idx].producto = e.target.value;
                 n[idx].fotoSugerida = buscarMatch(e.target.value);
                 setFilas(n);
               }}/></td>
               <td style={tdCell}><input style={inputTable} type="number" value={f.precioNuevo} onChange={e => {const n = [...filas]; n[n.findIndex(x => x.id === f.id)].precioNuevo = e.target.value; setFilas(n);}}/></td>
               <td style={tdCell}><input style={inputTable} type="number" value={f.precioViejo} onChange={e => {const n = [...filas]; n[n.findIndex(x => x.id === f.id)].precioViejo = e.target.value; setFilas(n);}}/></td>
               <td style={tdCell}><input style={inputTable} type="number" value={f.stock} onChange={e => {const n = [...filas]; n[n.findIndex(x => x.id === f.id)].stock = e.target.value; setFilas(n);}}/></td>
               </tr>
             ))}
           </tbody>
        </table>
        <div style={{padding: '20px', display:'flex', justifyContent:'space-between', background:'#f8fafc'}}>
            <div style={{display:'flex', gap:'10px'}}>
                <input type="date" onChange={e => setFechas({...fechas, inicio: e.target.value})} style={{padding:'8px', borderRadius:'8px', border:'1px solid #ddd'}}/>
                <input type="date" onChange={e => setFechas({...fechas, fin: e.target.value})} style={{padding:'8px', borderRadius:'8px', border:'1px solid #ddd'}}/>
            </div>
            <button onClick={publicarOfertas} style={btnNuevaSucursalCustom}>Publicar Ahora</button>
        </div>
      </div>

      {/* SECCIÓN 2: LO QUE YA ESTÁ PUBLICADO (AQUÍ ES DONDE VES TUS PRODUCTOS) */}
      <div style={{marginTop: '50px'}}>
        <h2 style={{...sidebarTitle, fontSize: '1.4rem', marginBottom: '20px'}}><Eye color="#1e293b"/> Productos Publicados en este Local</h2>
        <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px'}}>
          {publicados.length === 0 && <p style={{color:'#94a3b8'}}>No hay productos publicados todavía.</p>}
          {publicados.map(p => (
            <div key={p._id} style={{background: 'white', padding: '15px', borderRadius: '20px', border: '1px solid #e2e8f0', position: 'relative'}}>
              <button onClick={() => eliminarOferta(p._id)} style={{position:'absolute', top:'10px', right:'10px', border:'none', background:'#fee2e2', color:'#ef4444', borderRadius:'50%', width:'30px', height:'30px', cursor:'pointer'}}><Trash size={14}/></button>
              <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_200,h_150,c_fill/v1/${p.publicId}`} style={{width:'100%', height:'120px', objectFit:'cover', borderRadius:'12px', marginBottom:'10px'}} alt={p.producto}/>
              <h4 style={{margin: '5px 0', color: '#1e293b'}}>{p.producto}</h4>
              <div style={{display:'flex', gap:'10px', alignItems:'baseline'}}>
                <span style={{fontWeight:'bold', color:'#e67e22', fontSize:'1.1rem'}}>${p.precioNuevo}</span>
                <span style={{textDecoration:'line-through', color:'#94a3b8', fontSize:'0.8rem'}}>${p.precioViejo}</span>
              </div>
              <p style={{fontSize:'0.8rem', color:'#64748b', marginTop:'5px'}}>Stock: {p.stock} | {p.categoria}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default GestionOfertas;
